import {useEffect,useState} from 'react';
interface Props{initial?:string;onSave:(v:string)=>Promise<void>}
export function AutoSaveInput({initial='',onSave}:Props){
  const [value,setValue]=useState(initial); // always defined string
  useEffect(()=>{
    const t=setTimeout(()=>{onSave(value).catch(()=>{});},500);
    return ()=>clearTimeout(t);
  },[value,onSave]);
  return <input value={value} onChange={(e)=>setValue(e.target.value)}/>;
}

