import type {RequestHandler} from 'express';
import type {Pool} from 'pg';
export function listProducts(db:Pool):RequestHandler{
  return async(req,res)=>{
    const {category,page=1,perPage=20}=req.query as Record<string,string>;
    const offset=(Number(page)-1)*Number(perPage);
    const params:unknown[]=[];
    const where=category?(params.push(category),`WHERE category=$${params.length}`):'';
    params.push(Number(perPage),offset);
    const r=await db.query<{id:string;name:string;total:number}>(
      `SELECT id, name, COUNT(*) OVER () AS total FROM products ${where} ORDER BY name LIMIT $${params.length-1} OFFSET $${params.length}`,
      params
    );
    const total=r.rows[0]?.total??0;
    res.json({items:r.rows.map(({total:_,...rest})=>rest),total:Number(total)});
  };
}

