import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {splitEvenly} from './split';

describe('splitEvenly properties',()=>{
  it('shares sum to total',()=>{
    fc.assert(fc.property(fc.integer({min:0,max:1_000_000_000}),fc.integer({min:1,max:1000}),(total,n)=>{
      return splitEvenly(total,n).reduce((s,v)=>s+v,0)===total;
    }),{numRuns:1000});
  });
  it('shares differ by at most 1 cent (fair split)',()=>{
    fc.assert(fc.property(fc.integer({min:0,max:1_000_000_000}),fc.integer({min:1,max:1000}),(total,n)=>{
      const shares=splitEvenly(total,n);
      const max=Math.max(...shares);
      const min=Math.min(...shares);
      return max-min<=1;
    }),{numRuns:1000});
  });
  it('returns exactly n shares',()=>{
    fc.assert(fc.property(fc.integer({min:0,max:1_000_000}),fc.integer({min:1,max:100}),(total,n)=>{
      return splitEvenly(total,n).length===n;
    }),{numRuns:300});
  });
});

