const WEBHOOK_SECRET=process.env.STRIPE_WEBHOOK_SECRET_TEST!;

function signEvent(payload:string,secret:string):string{
  const ts=Math.floor(Date.now()/1000);
  const v1=crypto.createHmac('sha256',secret).update(`${ts}.${payload}`).digest('hex');
  return `t=${ts},v1=${v1}`;
}

