import {createContext,useContext,useState,useCallback,useEffect} from 'react';
interface Toast{id:string;message:string;ttl:number}
const Ctx=createContext<{push:(t:Omit<Toast,'id'>)=>void}|null>(null);

export function ToastProvider({children}:{children:React.ReactNode}){
  const [toasts,setToasts]=useState<Toast[]>([]);
  const push=useCallback((t:Omit<Toast,'id'>)=>{
    setToasts(prev=>{
      // Dedup by message — replace existing with same text
      const filtered=prev.filter(x=>x.message!==t.message);
      return [...filtered,{...t,id:crypto.randomUUID()}];
    });
  },[]);
  useEffect(()=>{
    const timers=toasts.map(t=>setTimeout(()=>setToasts(p=>p.filter(x=>x.id!==t.id)),t.ttl));
    return ()=>timers.forEach(clearTimeout);
  },[toasts]);
  return (
    <Ctx.Provider value={{push}}>
      {children}
      <div role="region" aria-label="notifications">
        {toasts.map(t=>(
          <div key={t.id} role="status">
            {t.message}
            <button onClick={()=>setToasts(p=>p.filter(x=>x.id!==t.id))} aria-label="dismiss">×</button>
          </div>
        ))}
      </div>
    </Ctx.Provider>
  );
}
export const useToast=()=>{const c=useContext(Ctx);if(!c)throw new Error('useToast outside provider');return c;};

