import type {Clock} from '../clock';

export class ApiClient{
  constructor(private opts:{baseUrl:string;clock:Clock;maxRetries?:number;sleep?:(ms:number)=>Promise<void>}){}
  async request(path:string,init?:RequestInit):Promise<Response>{
    const max=this.opts.maxRetries??5;
    const sleep=this.opts.sleep??((ms)=>new Promise(r=>setTimeout(r,ms)));
    for(let attempt=0;attempt<=max;attempt++){
      const r=await fetch(`${this.opts.baseUrl}${path}`,init);
      if(r.status!==429)return r;
      if(attempt===max)return r;
      const retryAfter=Number(r.headers.get('retry-after')??'1');
      const backoff=Math.min(retryAfter*1000*2**attempt,30_000);
      const jitter=Math.floor(Math.random()*200);
      await sleep(backoff+jitter);
    }
    throw new Error('unreachable');
  }
}

