const ENTITY=/[<>&"']/g;
const MAP:Record<string,string>={'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;',"'":'&#39;'};
export function escapeHtml(s:string):string{
  return s.replace(ENTITY,(c)=>MAP[c]);
}

// src/util/escape-html.property.test.ts
import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {escapeHtml} from './escape-html';

describe('escapeHtml properties',()=>{
  it('output contains no raw <, >',()=>{
    fc.assert(fc.property(fc.string(),(s)=>{
      const out=escapeHtml(s);
      return !out.includes('<')&&!out.includes('>');
    }),{numRuns:500});
  });
  it('unicode preserved',()=>{
    fc.assert(fc.property(fc.fullUnicodeString(),(s)=>{
      const safe=s.replace(/[<>&"']/g,'');
      const out=escapeHtml(safe);
      return out===safe;
    }),{numRuns:300});
  });
  it('is NOT idempotent because & becomes &amp; (documents intent)',()=>{
    // Idempotent escape would re-encode & — that's the bug
    // Document: this implementation deliberately encodes every & once per call
    expect(escapeHtml('a&b')).toBe('a&amp;b');
    expect(escapeHtml(escapeHtml('a&b'))).toBe('a&amp;amp;b');
    // Therefore: never call escapeHtml on already-escaped strings
  });
});

