import cronParser from 'cron-parser';
import type {Clock} from '../clock';

export function shouldRunAt(cronExpr:string,prevRun:number,now:number):boolean{
  const interval=cronParser.parseExpression(cronExpr,{currentDate:new Date(prevRun),tz:'UTC'});
  const next=interval.next().getTime();
  return now>=next;
}

export async function nightlyJob(clock:Clock,doWork:(now:number)=>Promise<void>):Promise<void>{
  await doWork(clock.now());
}

