import {useEffect,useState} from 'react';
interface Stream<T>{subscribe(cb:(v:T)=>void):()=>void}
export function useStream<T>(stream:Stream<T>):T|null{
  const [value,setValue]=useState<T|null>(null);
  useEffect(()=>{
    return stream.subscribe(setValue);
  },[stream]);
  return value;
}

// src/data/useStream.test.tsx
import {describe,it,expect,vi} from 'vitest';
import {renderHook,act} from '@testing-library/react';
import {useStream} from './useStream';

function makeStream(){
  const subs=new Set<(v:number)=>void>();
  return {
    subscribe(cb:(v:number)=>void){subs.add(cb);return ()=>subs.delete(cb);},
    emit(v:number){subs.forEach(cb=>cb(v));},
    get count(){return subs.size;}
  };
}

describe('useStream cleanup',()=>{
  it('unsubscribes on unmount (REGRESSION GUARD)',()=>{
    const stream=makeStream();
    const {unmount}=renderHook(()=>useStream(stream));
    expect(stream.count).toBe(1);
    unmount();
    expect(stream.count).toBe(0);
  });
  it('does not setState after unmount',()=>{
    const stream=makeStream();
    const {result,unmount}=renderHook(()=>useStream(stream));
    unmount();
    act(()=>stream.emit(42)); // Should NOT trigger setState
    expect(result.current).toBeNull();
  });
  it('changing stream prop unsubscribes from old, subscribes to new',()=>{
    const a=makeStream();
    const b=makeStream();
    const {rerender}=renderHook(({s})=>useStream(s),{initialProps:{s:a}});
    expect(a.count).toBe(1);
    rerender({s:b});
    expect(a.count).toBe(0);
    expect(b.count).toBe(1);
  });
});

