export type Selected<T,K extends keyof T>=Pick<T,K>;
export function select<T,K extends keyof T>(obj:T,keys:K[]):Selected<T,K>{
  const out={} as Selected<T,K>;
  for(const k of keys)out[k]=obj[k];
  return out;
}

