interface MQL{matches:boolean;media:string;addEventListener:(e:string,cb:(ev:{matches:boolean})=>void)=>void;removeEventListener:(e:string,cb:(ev:{matches:boolean})=>void)=>void}
const registry=new Map<string,Set<(ev:{matches:boolean})=>void>>();
const values=new Map<string,boolean>();

export function setMatchMedia(query:string,matches:boolean):void{
  values.set(query,matches);
  registry.get(query)?.forEach(cb=>cb({matches}));
}

Object.defineProperty(window,'matchMedia',{
  writable:true,
  value:(query:string):MQL=>{
    if(!registry.has(query))registry.set(query,new Set());
    return {
      get matches(){return values.get(query)??false;},
      media:query,
      addEventListener:(_e,cb)=>{registry.get(query)!.add(cb);},
      removeEventListener:(_e,cb)=>{registry.get(query)!.delete(cb);}
    };
  }
});

