export class SortedList<T>{
  private items:T[]=[];
  constructor(private cmp:(a:T,b:T)=>number){}
  insert(v:T):void{
    let lo=0,hi=this.items.length;
    while(lo<hi){
      const mid=(lo+hi)>>>1;
      if(this.cmp(this.items[mid],v)<=0)lo=mid+1;
      else hi=mid;
    }
    this.items.splice(lo,0,v);
  }
  toArray():T[]{return [...this.items];}
}

