import {describe,it} from 'vitest';
import fc from 'fast-check';
import {SortedList} from './sorted-list';

describe('SortedList properties',()=>{
  it('always sorted after any insertion sequence',()=>{
    fc.assert(fc.property(fc.array(fc.integer(),{maxLength:100}),(vals)=>{
      const list=new SortedList<number>((a,b)=>a-b);
      for(const v of vals)list.insert(v);
      const arr=list.toArray();
      for(let i=1;i<arr.length;i++)if(arr[i]<arr[i-1])return false;
      return true;
    }),{numRuns:500});
  });
  it('stable: equal keys preserve insertion order',()=>{
    fc.assert(fc.property(fc.array(fc.tuple(fc.integer({min:0,max:5}),fc.nat()),{maxLength:50}),(pairs)=>{
      const list=new SortedList<[number,number]>((a,b)=>a[0]-b[0]);
      for(const p of pairs)list.insert(p);
      const arr=list.toArray();
      // For each key group, verify the original insertion order preserved
      for(let i=1;i<arr.length;i++){
        if(arr[i][0]===arr[i-1][0]){
          // Find original positions
          const a=pairs.findIndex(p=>p===arr[i-1]);
          const b=pairs.findIndex(p=>p===arr[i]);
          if(a>=b)return false;
        }
      }
      return true;
    }),{numRuns:300});
  });
});

