export interface Handshake{version:number;flags:number;sessionId:Buffer}
export function parseHandshake(buf:Buffer):Handshake{
  if(buf.length<10)throw new Error('too short');
  return {
    version:buf.readUInt8(0),
    flags:buf.readUInt8(1),
    sessionId:buf.subarray(2,10)
  };
}

