import {Suspense,use} from 'react';
import {ErrorBoundary} from '../ui/ErrorBoundary';
export function AsyncSection<T>({promise,render}:{promise:Promise<T>;render:(v:T)=>React.ReactNode}){
  function Inner(){const v=use(promise);return <>{render(v)}</>;}
  return (
    <ErrorBoundary fallback={({error,reset})=><div role="alert">Error: {error.message}<button onClick={reset}>Retry</button></div>}>
      <Suspense fallback={<div role="status">loading…</div>}>
        <Inner/>
      </Suspense>
    </ErrorBoundary>
  );
}

